#include <stdio.h>
int max(int a, int b) { return a > b ? a : b; }
int ninjaTraining(int n, int points[][3]) {
    int dp[n][3];
    dp[0][0] = points[0][1];
    dp[0][1] = points[0][0];
    dp[0][2] = points[0][0];
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < 3; j++) {
            int max_val = 0;
            for (int k = 0; k < 3; k++) {
                if (k != j) {
                    max_val = max(max_val, dp[i-1][k]);
                }
            }
            dp[i][j] = max_val + points[i][j];
        }
    }
    int max_val = 0;
    for (int i = 0; i < 3; i++) {
        max_val = max(max_val, dp[n-1][i]);
    }
    return max_val;
}
int main() {
    int n;
    scanf("%d", &n);
    int points[n][3];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < 3; j++) {
            scanf("%d", &points[i][j]);
        }
    }
    printf("%d\n", ninjaTraining(n, points));
    return 0;
}

