function ninjaTraining(n, points) {
    let dp = Array.from({length: n}, () => Array(3).fill(0));
    dp[0][0] = Math.max(points[0][1], points[0][2]);
    dp[0][1] = Math.max(points[0][0], points[0][2]);
    dp[0][2] = Math.max(points[0][0], points[0][1]);
    for (let i = 1; i < n; i++) {
        for (let j = 0; j < 3; j++) {
            let max_val = 0;
            for (let k = 0; k < 3; k++) {
                if (k !== j) {
                    max_val = Math.max(max_val, dp[i-1][k]);
                }
            }
            dp[i][j] = max_val + points[i][j];
        }
    }
    let max_val = 0;
    for (let i = 0; i < 3; i++) {
        max_val = Math.max(max_val, dp[n-1][i]);
    }
    return max_val;
}

